sql:
SELECT site_id, AVG(upper_cm) AS avg_upper_depth, AVG(lower_cm) AS avg_lower_depth
FROM soil_samples
GROUP BY site_id;

SELECT sample_id
FROM soil_samples
WHERE sample_id NOT IN (
  SELECT sample_id 
  FROM sample_project_links
);

SELECT *
FROM measurements
WHERE soc_pct > (SELECT AVG(soc_pct) FROM measurements);

SELECT sample_id, site_id, protocol_id 
FROM soil_samples 
WHERE replicate > 1;

SELECT COUNT(sample_id) 
FROM soil_samples 
WHERE collector_id = 1;

external_knowledge:
'sown the seeds of organic carbon growth' figuratively refers to projects that have contributed to an increase in soil organic carbon;
'average yields' metaphorically represents the average SOC (Soil Organic Carbon) percentage;
'chosen garden of site 1' translates to the specific site with site_id = 1.

- Shallow layers (10 to 20 cm depth) imply sample collection from the uppermost part of the soil profile; 
- Moderate moisture is typically between 5% and 15%; 
- Neutral pH levels are within the range of 6 to 8; 
- 'Soil Sciences' expertise indicates the researcher's specialization in soil-related studies.

sql:
SELECT soil_samples.sample_id, sites.site_name
FROM soil_samples
INNER JOIN sites ON soil_samples.site_id = sites.site_id;

SELECT protocol_id, site_id
FROM soil_samples
WHERE site_id IN (SELECT site_id FROM sites);

SELECT protocol_name
FROM protocols
WHERE protocol_id = (SELECT protocol_id FROM soil_samples WHERE sample_id = 1);
